  1→/**
  2→ * algorithm-state.ts — Single source of truth for algorithm state management.
  3→ *
  4→ * ALL state writes go through this module. No other code writes to algorithm
  5→ * state files directly.
  6→ *
  7→ * Architecture:
  8→ *   Per-session files: MEMORY/STATE/algorithms/{sessionId}.json
  9→ *   One file per session. Multiple runs tracked via phaseHistory resets.
 10→ *
 11→ * Writers (1 hook, 1 handler):
 12→ *   AlgorithmTracker (PostToolUse: Bash,TaskCreate,TaskUpdate,Task)
 13→ *     → phaseTransition(), criteriaAdd(), criteriaUpdate(), agentAdd(), effortLevelUpdate()
 14→ *     → Real-time effort level inference: upgrades from 'Standard' based on criteria count
 15→ *       (>=12 → Extended, >=20 → Advanced, >=40 → Deep)
 16→ *   AlgorithmEnrichment (Stop handler in StopOrchestrator)
 17→ *     → algorithmEnd(), sweepStaleActive()
 18→ *     → Multi-pattern regex extraction + heuristic fallback for effort level
 19→ */
 20→
 21→import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
 22→import { join } from 'path';
 23→
 24→// ── Types ──
 25→
 26→export type AlgorithmPhase = 'OBSERVE' | 'THINK' | 'PLAN' | 'BUILD' | 'EXECUTE' | 'VERIFY' | 'LEARN' | 'IDLE' | 'COMPLETE';
 27→
 28→export interface AlgorithmCriterion {
 29→  id: string;
 30→  description: string;
 31→  type: 'criterion' | 'anti-criterion';
 32→  status: 'pending' | 'in_progress' | 'completed' | 'failed';
 33→  evidence?: string;
 34→  createdInPhase: AlgorithmPhase;
 35→  taskId?: string;
 36→}
 37→
 38→export interface PhaseEntry {
 39→  phase: AlgorithmPhase;
 40→  startedAt: number;
 41→  completedAt?: number;
 42→  criteriaCount: number;
 43→  agentCount: number;
 44→  /** True if this phase visit is part of a rework cycle */
 45→  isRework?: boolean;
 46→  /** Which rework iteration (0 = initial run, 1+ = rework) */
 47→  reworkIteration?: number;
 48→}
 49→
 50→/** Archive of a completed algorithm cycle (preserved during rework) */
 51→export interface ReworkCycle {
 52→  iteration: number;
 53→  startedAt: number;
 54→  completedAt: number;
 55→  fromPhase: AlgorithmPhase;
 56→  toPhase: AlgorithmPhase;
 57→  criteria: AlgorithmCriterion[];
 58→  summary?: string;
 59→  effortLevel: string;
 60→  phaseHistory: PhaseEntry[];
 61→}
 62→
 63→export interface AlgorithmAgent {
 64→  name: string;
 65→  agentType: string;
 66→  status: 'active' | 'completed' | 'failed' | string;
 67→  task?: string;
 68→  criteriaIds?: string[];
 69→  phase?: AlgorithmPhase | string;
 70→}
 71→
 72→export interface AlgorithmState {
 73→  active: boolean;
 74→  sessionId: string;
 75→  taskDescription: string;
 76→  currentPhase: AlgorithmPhase;
 77→  phaseStartedAt: number;
 78→  algorithmStartedAt: number;
 79→  sla: 'Instant' | 'Fast' | 'Standard' | 'Extended' | 'Advanced' | 'Deep' | 'Comprehensive' | 'Loop';
 80→  /** Canonical field name — same value as sla, preferred by UI */
 81→  effortLevel?: 'Instant' | 'Fast' | 'Standard' | 'Extended' | 'Advanced' | 'Deep' | 'Comprehensive' | 'Loop';
 82→  criteria: AlgorithmCriterion[];
 83→  agents: AlgorithmAgent[];
 84→  capabilities: string[];
 85→  prdPath?: string;
 86→  phaseHistory: PhaseEntry[];
 87→  qualityGate?: {
 88→    count: boolean;
 89→    length: boolean;
 90→    state: boolean;
 91→    testable: boolean;
 92→    anti: boolean;
 93→    open: boolean;
 94→  };
 95→  currentAction?: string;
 96→  completedAt?: number;
 97→  summary?: string;
 98→  abandoned?: boolean;
 99→  /** Number of times this session re-entered the algorithm after completion */
100→  reworkCount?: number;
101→  /** True when currently in a rework cycle (vs initial run) */
102→  isRework?: boolean;
103→  /** Archive of each completed algorithm cycle */
104→  reworkHistory?: ReworkCycle[];
105→  /** History of session name changes on rework (for dashboard display) */
106→  previousNames?: Array<{ name: string; changedAt: string }>;
107→  /** Loop mode: true when this state represents a Loop runner session */
108→  loopMode?: boolean;
109→  /** Loop mode: current iteration number */
110→  loopIteration?: number;
111→  /** Loop mode: max allowed iterations */
112→  loopMaxIterations?: number;
113→  /** Loop mode: PRD identifier */
114→  loopPrdId?: string;
115→  /** Loop mode: absolute path to PRD file */
116→  loopPrdPath?: string;
117→  /** Loop mode: per-iteration progress history */
118→  loopHistory?: Array<{
119→    iteration: number;
120→    startedAt: number;
121→    completedAt: number;
122→    criteriaPassing: number;
123→    criteriaTotal: number;
124→    sdkSessionId?: string;
125→  }>;
126→  /** Parallel agents: number of concurrent agents configured via -a flag */
127→  parallelAgents?: number;
128→  /** Execution mode: distinguishes loop/interactive/standard for dashboard display */
129→  mode?: 'loop' | 'interactive' | 'standard';
130→}
131→
132→// ── Paths ──
133→
134→const BASE_DIR = process.env.PAI_DIR || join(process.env.HOME!, '.claude');
135→const ALGORITHMS_DIR = join(BASE_DIR, 'MEMORY', 'STATE', 'algorithms');
136→const SESSION_NAMES_PATH = join(BASE_DIR, 'MEMORY', 'STATE', 'session-names.json');
137→
138→function ensureDir(): void {
139→  if (!existsSync(ALGORITHMS_DIR)) mkdirSync(ALGORITHMS_DIR, { recursive: true });
140→}
141→
142→// ── Read / Write ──
143→
144→export function readState(sessionId: string): AlgorithmState | null {
145→  try {
146→    const file = join(ALGORITHMS_DIR, `${sessionId}.json`);
147→    if (!existsSync(file)) return null;
148→    const raw = readFileSync(file, 'utf-8').trim();
149→    if (!raw || raw === '{}') return null;
150→    return JSON.parse(raw) as AlgorithmState;
151→  } catch {
152→    return null;
153→  }
154→}
155→
156→const PLACEHOLDER_RE = /^(Starting\.{0,3}|Algorithm run|[0-9a-f]{8})$/i;
157→function isPlaceholderName(name: string): boolean {
158→  return PLACEHOLDER_RE.test(name);
159→}
160→
161→export function writeState(state: AlgorithmState): void {
162→  ensureDir();
163→  // Keep effortLevel in sync with sla — UI reads effortLevel preferentially
164→  state.effortLevel = state.sla;
165→  // Re-check session-names.json for name updates (placeholder fix + rework rejuvenation)
166→  const latestName = getSessionName(state.sessionId);
167→  if (!isPlaceholderName(latestName) && latestName !== state.taskDescription) {
168→    state.taskDescription = latestName;
169→  }
170→  writeFileSync(join(ALGORITHMS_DIR, `${state.sessionId}.json`), JSON.stringify(state, null, 2));
171→}
172→
173→function getSessionName(sessionId: string): string {
174→  try {
175→    if (existsSync(SESSION_NAMES_PATH)) {
176→      const names = JSON.parse(readFileSync(SESSION_NAMES_PATH, 'utf-8'));
177→      if (names[sessionId]) return names[sessionId];
178→    }
179→  } catch {}
180→  return 'Algorithm run';
181→}
182→
183→// ── Public API ──
184→
185→/**
186→ * Called when a phase transition curl is detected (e.g., "Entering the Think phase").
187→ */
188→export function phaseTransition(sessionId: string, phase: AlgorithmPhase): void {
189→  const now = Date.now();
190→  let state = readState(sessionId);
191→
192→  if (!state) {
193→    // No state yet — create one (algorithm entry curl may have been missed)
194→    state = {
195→      active: true,
196→      sessionId,
197→      taskDescription: getSessionName(sessionId),
198→      currentPhase: phase,
199→      phaseStartedAt: now,
200→      algorithmStartedAt: now,
201→      sla: 'Standard',
202→      criteria: [],
203→      agents: [],
204→      capabilities: ['Task Tool'],
205→      phaseHistory: [{ phase, startedAt: now, criteriaCount: 0, agentCount: 0 }],
206→    };
207→    writeState(state);
208→    return;
209→  }
210→
211→  // New algorithm run within same session?
212→  const isNewRun = phase === 'OBSERVE' &&
213→    (state.currentPhase === 'LEARN' || state.currentPhase === 'COMPLETE' || state.currentPhase === 'IDLE');
214→
215→  if (isNewRun) {
216→    // Detect rework: session had previous work (criteria or summary = evidence of completed run)
217→    const hasPreviousWork = state.criteria.length > 0 || !!state.summary;
218→
219→    if (hasPreviousWork) {
220→      // Archive current cycle into reworkHistory
221→      const cycle: ReworkCycle = {
222→        iteration: (state.reworkCount ?? 0),
223→        startedAt: state.algorithmStartedAt,
224→        completedAt: state.completedAt || now,
225→        fromPhase: state.currentPhase,
226→        toPhase: phase,
227→        criteria: [...state.criteria],
228→        summary: state.summary,
229→        effortLevel: state.sla,
230→        phaseHistory: [...state.phaseHistory],
231→      };
232→      if (!state.reworkHistory) state.reworkHistory = [];
233→      state.reworkHistory.push(cycle);
234→      state.reworkCount = (state.reworkCount ?? 0) + 1;
235→      state.isRework = true;
236→    }
237→
238→    state.active = true;
239→    state.currentPhase = phase;
240→    state.phaseStartedAt = now;
241→    state.algorithmStartedAt = now;
242→    state.criteria = [];
243→    state.capabilities = ['Task Tool'];
244→    const reworkIter = state.reworkCount ?? 0;
245→    state.phaseHistory = [{ phase, startedAt: now, criteriaCount: 0, agentCount: 0, isRework: reworkIter > 0, reworkIteration: reworkIter }];
246→    delete state.completedAt;
247→    delete state.summary;
248→    delete state.qualityGate;
249→    writeState(state);
250→    return;
251→  }
252→
253→  // Normal phase transition — close previous, open new
254→  if (state.phaseHistory.length > 0) {
255→    const last = state.phaseHistory[state.phaseHistory.length - 1];
256→    if (!last.completedAt) last.completedAt = now;
257→  }
258→
259→  const reworkIter = state.reworkCount ?? 0;
260→  state.phaseHistory.push({
261→    phase,
262→    startedAt: now,
263→    criteriaCount: state.criteria.length,
264→    agentCount: state.agents.filter((a: any) => a.status === 'active').length,
265→    ...(reworkIter > 0 && { isRework: true, reworkIteration: reworkIter }),
266→  });
267→
268→  state.active = true;
269→  state.currentPhase = phase;
270→  state.phaseStartedAt = now;
271→
272→  // LEARN sets completedAt for grace period display but stays active
273→  // until the Stop handler calls algorithmEnd()
274→  if (phase === 'LEARN') {
275→    state.completedAt = now;
276→  }
277→
278→  writeState(state);
279→}
280→
281→/**
282→ * Called when TaskCreate produces an ISC criterion.
283→ * Also handles session reactivation — ISC criteria arriving for a completed
284→ * session is a definitive signal of a new algorithm run.
285→ */
286→export function criteriaAdd(sessionId: string, criterion: AlgorithmCriterion): void {
287→  let state = readState(sessionId);
288→
289→  // Create state if none exists — ISC criteria in a new session should not be dropped
290→  if (!state) {
291→    const now = Date.now();
292→    state = {
293→      active: true,
294→      sessionId,
295→      taskDescription: getSessionName(sessionId),
296→      currentPhase: 'OBSERVE' as AlgorithmPhase,
297→      phaseStartedAt: now,
298→      algorithmStartedAt: now,
299→      sla: 'Standard' as AlgorithmState['sla'],
300→      criteria: [],
301→      agents: [],
302→      capabilities: ['Task Tool'],
303→      phaseHistory: [{ phase: 'OBSERVE' as AlgorithmPhase, startedAt: now, criteriaCount: 0, agentCount: 0 }],
304→    };
305→  }
306→
307→  // Reactivate completed session — new ISC criteria = new algorithm run
308→  if (!state.active) {
309→    const now = Date.now();
310→    const hasPreviousWork = state.criteria.length > 0 || !!state.summary;
311→
312→    // Archive previous cycle if it had work (rework detection)
313→    if (hasPreviousWork) {
314→      const cycle: ReworkCycle = {
315→        iteration: (state.reworkCount ?? 0),
316→        startedAt: state.algorithmStartedAt,
317→        completedAt: state.completedAt || now,
318→        fromPhase: state.currentPhase,
319→        toPhase: 'OBSERVE',
320→        criteria: [...state.criteria],
321→        summary: state.summary,
322→        effortLevel: state.sla,
323→        phaseHistory: [...state.phaseHistory],
324→      };
325→      if (!state.reworkHistory) state.reworkHistory = [];
326→      state.reworkHistory.push(cycle);
327→      state.reworkCount = (state.reworkCount ?? 0) + 1;
328→      state.isRework = true;
329→    }
330→
331→    const reworkIter = state.reworkCount ?? 0;
332→    state = {
333→      ...state,
334→      active: true,
335→      currentPhase: 'OBSERVE' as AlgorithmPhase,
336→      phaseStartedAt: now,
337→      algorithmStartedAt: now,
338→      sla: 'Standard' as AlgorithmState['sla'],
339→      criteria: [],
340→      capabilities: ['Task Tool'],
341→      phaseHistory: [{ phase: 'OBSERVE' as AlgorithmPhase, startedAt: now, criteriaCount: 0, agentCount: 0, isRework: reworkIter > 0, reworkIteration: reworkIter }],
342→      agents: [],
343→    };
344→    delete state.completedAt;
345→    delete state.summary;
346→    delete state.qualityGate;
347→  }
348→
349→  // Don't add duplicates
350→  if (state.criteria.some(c => c.id === criterion.id)) return;
351→
352→  state.criteria.push(criterion);
353→  writeState(state);
354→}
355→
356→/**
357→ * Called when TaskUpdate changes a criterion's status.
358→ */
359→export function criteriaUpdate(sessionId: string, taskId: string, status: AlgorithmCriterion['status']): void {
360→  const state = readState(sessionId);
361→  if (!state) return;
362→
363→  const criterion = state.criteria.find(c => c.taskId === taskId);
364→  if (!criterion) return;
365→
366→  criterion.status = status;
367→  writeState(state);
368→}
369→
370→/**
371→ * Called when the Algorithm's OBSERVE phase selects an effort level.
372→ * Detected in real-time by AlgorithmTracker from response text.
373→ */
374→export function effortLevelUpdate(sessionId: string, level: AlgorithmState['sla']): void {
375→  const state = readState(sessionId);
376→  if (!state) return;
377→
378→  state.sla = level;
379→  writeState(state);
380→}
381→
382→/**
383→ * Called when a Task tool spawns an agent.
384→ */
385→export function agentAdd(sessionId: string, agent: { name: string; agentType: string; task?: string; criteriaIds?: string[] }): void {
386→  const state = readState(sessionId);
387→  if (!state) return;
388→
389→  // Don't add duplicates
390→  if (state.agents.some(a => a.name === agent.name)) return;
391→
392→  const entry: AlgorithmAgent = {
393→    name: agent.name,
394→    agentType: agent.agentType,
395→    status: 'active',
396→    task: agent.task,
397→    phase: state.currentPhase,
398→  };
399→  if (agent.criteriaIds) entry.criteriaIds = agent.criteriaIds;
400→  state.agents.push(entry);
401→  writeState(state);
402→}
403→
404→/**
405→ * Called by Stop handler after response is complete.
406→ * Enriches state with data extracted from the full transcript.
407→ *
408→ * Two modes:
409→ * - isAlgorithmResponse=true: Enrich with extracted data, mark terminal if LEARN/COMPLETE
410→ * - isAlgorithmResponse=false: Deactivate optimistically-activated sessions
411→ */
412→export function algorithmEnd(
413→  sessionId: string,
414→  enrichment: {
415→    taskDescription?: string;
416→    summary?: string;
417→    sla?: AlgorithmState['sla'];
418→    capabilities?: string[];
419→    qualityGate?: AlgorithmState['qualityGate'];
420→    criteria?: AlgorithmCriterion[];
421→    isAlgorithmResponse: boolean;
422→  }
423→): void {
424→  let state = readState(sessionId);
425→
426→  // Non-algorithm response: deactivate if it was optimistically activated
427→  if (!enrichment.isAlgorithmResponse) {
428→    if (state && state.active && state.phaseHistory.length <= 1 && state.criteria.length === 0) {
429→      // Session was activated by SessionReactivator but response wasn't algorithm format.
430→      // Deactivate to prevent stale active sessions.
431→      state.active = false;
432→      state.currentPhase = 'COMPLETE';
433→      state.completedAt = Date.now();
434→      writeState(state);
435→    }
436→    return;
437→  }
438→
439→  // No state file yet — create one
440→  if (!state) {
441→    state = {
442→      active: true,
443→      sessionId,
444→      taskDescription: enrichment.taskDescription || getSessionName(sessionId),
445→      currentPhase: 'OBSERVE',
446→      phaseStartedAt: Date.now(),
447→      algorithmStartedAt: Date.now(),
448→      sla: enrichment.sla || 'Standard',
449→      criteria: [],
450→      agents: [],
451→      capabilities: ['Task Tool'],
452→      phaseHistory: [],
453→    };
454→  }
455→
456→  // Enrich with extracted data
457→  if (enrichment.taskDescription) {
458→    state.taskDescription = enrichment.taskDescription;
459→    state.currentAction = enrichment.taskDescription;
460→  }
461→  if (enrichment.summary) state.summary = enrichment.summary;
462→  if (enrichment.sla) state.sla = enrichment.sla;
463→  if (enrichment.capabilities && enrichment.capabilities.length > 0) {
464→    state.capabilities = enrichment.capabilities;
465→  }
466→  if (enrichment.qualityGate) state.qualityGate = enrichment.qualityGate;
467→
468→  // Merge criteria from transcript (catches any missed by real-time tracker)
469→  if (enrichment.criteria && enrichment.criteria.length > 0) {
470→    for (const c of enrichment.criteria) {
471→      const existing = state.criteria.find(ec => ec.id === c.id);
472→      if (existing) {
473→        const order = ['pending', 'in_progress', 'completed', 'failed'];
474→        if (order.indexOf(c.status) > order.indexOf(existing.status)) {
475→          existing.status = c.status;
476→          if (c.evidence) existing.evidence = c.evidence;
477→        }
478→      } else {
479→        state.criteria.push(c);
480→      }
481→    }
482→  }
483→
484→  // Terminal detection — response is done when phase reached LEARN or COMPLETE.
485→  // Summary extraction alone is NOT sufficient — during compaction, StopOrchestrator
486→  // fires with a partial transcript that may contain voice lines from earlier phases.
487→  // Only phase-based detection is reliable across compaction boundaries.
488→  const isTerminal = state.currentPhase === 'LEARN' || state.currentPhase === 'COMPLETE';
489→  if (isTerminal) {
490→    state.active = false;
491→    state.currentPhase = 'COMPLETE';
492→    state.completedAt = state.completedAt || Date.now();
493→  }
494→
495→  writeState(state);
496→}
497→
498→/**
499→ * Sweep all algorithm state files and mark stale active sessions as completed.
500→ * Called after every response by the StopOrchestrator handler.
501→ *
502→ * Phase-aware thresholds protect long-running work:
503→ * - BUILD/EXECUTE: 60min (art generation, multi-agent swarms, long processes)
504→ * - THINK/PLAN/VERIFY: 30min (extended reasoning, complex verification)
505→ * - OBSERVE/LEARN/IDLE/other: 15min (should complete quickly)
506→ *
507→ * File mtime is the staleness signal — updated by every tool call hook.
508→ * Loop items (PRDs) are NOT affected — they use a separate data store.
509→ */
510→const STALE_THRESHOLDS_MS: Record<string, number> = {
511→  BUILD: 60 * 60 * 1000,    // 60 min
512→  EXECUTE: 60 * 60 * 1000,  // 60 min
513→  THINK: 30 * 60 * 1000,    // 30 min
514→  PLAN: 30 * 60 * 1000,     // 30 min
515→  VERIFY: 30 * 60 * 1000,   // 30 min
516→};
517→const DEFAULT_STALE_MS = 15 * 60 * 1000; // 15 min for OBSERVE, LEARN, IDLE, etc.
518→
519→const DELETE_AGE_MS = 24 * 60 * 60 * 1000; // 24hr: completed files older than this get deleted
520→
521→export function sweepStaleActive(currentSessionId: string): void {
522→  try {
523→    ensureDir();
524→    const { readdirSync, statSync, unlinkSync } = require('fs') as typeof import('fs');
525→    const now = Date.now();
526→    const files = (readdirSync(ALGORITHMS_DIR) as string[]).filter(f => f.endsWith('.json'));
527→    const liveSessionIds = new Set<string>();
528→
529→    for (const file of files) {
530→      const sid = file.replace('.json', '');
531→      if (sid === currentSessionId) continue; // Skip current session — handled by algorithmEnd
532→
533→      try {
534→        const filepath = join(ALGORITHMS_DIR, file);
535→        const mtime = statSync(filepath).mtimeMs;
536→        const age = now - mtime;
537→
538→        const state = readState(sid);
539→        if (!state) continue;
540→
541→        // Delete completed files older than 24 hours — they clutter the directory
542→        if (!state.active && age > DELETE_AGE_MS) {
543→          try {
544→            unlinkSync(filepath);
545→            process.stderr.write(`[sweep] deleted ${sid} (completed, age ${Math.round(age / 3600000)}h)\n`);
546→          } catch {}
547→          continue;
548→        }
549→
550→        liveSessionIds.add(sid);
551→
552→        // Quick skip: anything modified in last 15 min is never stale
553→        if (age < DEFAULT_STALE_MS) continue;
554→
555→        if (!state.active) continue;
556→
557→        // Phase-aware threshold
558→        const threshold = STALE_THRESHOLDS_MS[state.currentPhase] || DEFAULT_STALE_MS;
559→        if (age < threshold) continue;
560→
561→        // Stale active session — mark completed
562→        state.active = false;
563→        state.currentPhase = 'COMPLETE';
564→        state.completedAt = state.completedAt || now;
565→        writeState(state);
566→        process.stderr.write(`[sweep] deactivated ${sid} (phase was ${state.currentPhase}, age ${Math.round(age / 60000)}min)\n`);
567→      } catch {}
568→    }
569→
570→    // Add current session to live set
571→    liveSessionIds.add(currentSessionId);
572→
573→    // Validate + sync session-names.json — repair if corrupted, prune orphans
574→    try {
575→      if (existsSync(SESSION_NAMES_PATH)) {
576→        const raw = readFileSync(SESSION_NAMES_PATH, 'utf-8').trim();
577→        const names = JSON.parse(raw) as Record<string, string>;
578→        const keys = Object.keys(names);
579→        let pruned = 0;
580→        for (const key of keys) {
581→          if (!liveSessionIds.has(key)) {
582→            delete names[key];
583→            pruned++;
584→          }
585→        }
586→        if (pruned > 0) {
587→          writeFileSync(SESSION_NAMES_PATH, JSON.stringify(names, null, 2));
588→          process.stderr.write(`[sweep] pruned ${pruned} orphaned entries from session-names.json\n`);
589→        }
590→      }
591→    } catch {
592→      process.stderr.write(`[sweep] session-names.json corrupt — resetting to {}\n`);
593→      writeFileSync(SESSION_NAMES_PATH, '{}');
594→    }
595→
596→  } catch {}
597→}
598→
599→/**
600→ * Called by POST /api/algorithm/abandon
601→ */
602→export function algorithmAbandon(sessionId: string): boolean {
603→  const state = readState(sessionId);
604→  if (!state) return false;
605→
606→  state.abandoned = true;
607→  state.active = false;
608→  state.completedAt = state.completedAt || Date.now();
609→  writeState(state);
610→  return true;
611→}
