 24→export type ChangeCategory =
 25→  | 'skill'
 26→  | 'hook'
 27→  | 'workflow'
 28→  | 'config'
 29→  | 'core-system'
 30→  | 'memory-system'
 31→  | 'documentation';
 32→
 33→export type SignificanceLabel = 'trivial' | 'minor' | 'moderate' | 'major' | 'critical';
 34→
 35→export type ChangeType =
 36→  | 'skill_update'
 37→  | 'structure_change'
 38→  | 'doc_update'
 39→  | 'hook_update'
 40→  | 'workflow_update'
 41→  | 'config_update'
 42→  | 'tool_update'
 43→  | 'multi_area';
 44→
 45→export interface IntegrityState {
 46→  last_run: string;
 47→  last_changes_hash: string;
 48→  cooldown_until: string | null;
 49→}
