 52→// Path Constants
 53→// ============================================================================
 54→
 55→const PAI_DIR = getPaiDir();
 56→const STATE_FILE = join(PAI_DIR, 'MEMORY', 'STATE', 'integrity-state.json');
 57→
 58→// Paths that are excluded from integrity checks
 59→const EXCLUDED_PATHS = [
 60→  'MEMORY/WORK/',
 61→  'MEMORY/LEARNING/',
 62→  'MEMORY/STATE/',
 63→  'scratch/',
 64→  'Plans/',
 65→  'projects/',
 66→  '.git/',
 67→  'node_modules/',
 68→  'ShellSnapshots/',
 69→];
 70→
 71→// High-priority paths that always warrant documentation
 72→const HIGH_PRIORITY_PATHS = [
 73→  'skills/PAI/',
 74→  'skills/PAI/USER/',
 75→  'PAISYSTEMARCHITECTURE.md',
 76→  'SKILLSYSTEM.md',
 77→  'MEMORYSYSTEM.md',
 78→  'THEHOOKSYSTEM.md',
 79→  'THEDELEGATIONSYSTEM.md',
 80→  'THENOTIFICATIONSYSTEM.md',
 81→  'settings.json',
 82→];
 83→
 84→// Philosophical/architectural patterns in paths
 85→const PHILOSOPHICAL_PATTERNS = [
 86→  /PAI\/SYSTEM\//i,
 87→  /PAI\/USER\//i,
 88→  /ARCHITECTURE/i,
 89→  /PRINCIPLES/i,
 90→  /FOUNDING/i,
 91→  /IDENTITY/i,
 92→];
 93→
 94→// Structural change patterns
 95→const STRUCTURAL_PATTERNS = [
 96→  /\/SKILL\.md$/i,           // Skill definitions
 97→  /\/Workflows\//i,          // Workflow routing
 98→  /settings\.json$/i,        // Configuration
 99→  /frontmatter/i,            // Metadata changes
100→];
