102→// ============================================================================
103→// Transcript Parsing
104→// ============================================================================
105→
106→/**
107→ * Parse tool_use blocks from a transcript that modify files.
108→ * Extracts Write, Edit, and MultiEdit operations.
109→ */
110→export function parseToolUseBlocks(transcriptPath: string): FileChange[] {
111→  try {
112→    if (!existsSync(transcriptPath)) {
113→      console.error('[ChangeDetection] Transcript not found:', transcriptPath);
114→      return [];
115→    }
116→
117→    const content = readFileSync(transcriptPath, 'utf-8');
118→    const lines = content.trim().split('\n');
119→    const changes: FileChange[] = [];
120→    const seenPaths = new Set<string>();
121→
122→    for (const line of lines) {
123→      if (!line.trim()) continue;
124→
125→      try {
126→        const entry = JSON.parse(line);
127→
128→        // Look for assistant messages with tool_use
129→        if (entry.type === 'assistant' && entry.message?.content) {
130→          const contentArray = Array.isArray(entry.message.content)
131→            ? entry.message.content
132→            : [];
133→
134→          for (const block of contentArray) {
135→            if (block.type !== 'tool_use') continue;
136→
137→            const toolName = block.name;
138→            const input = block.input || {};
139→
140→            // Handle Write, Edit, MultiEdit tools
141→            if (toolName === 'Write' && input.file_path) {
142→              const path = normalizeToRelativePath(input.file_path);
143→              if (!seenPaths.has(path)) {
144→                seenPaths.add(path);
145→                changes.push(createFileChange('Write', path));
146→              }
147→            } else if (toolName === 'Edit' && input.file_path) {
148→              const path = normalizeToRelativePath(input.file_path);
149→              if (!seenPaths.has(path)) {
150→                seenPaths.add(path);
151→                changes.push(createFileChange('Edit', path));
152→              }
153→            } else if (toolName === 'MultiEdit' && input.edits) {
154→              for (const edit of input.edits) {
155→                if (edit.file_path) {
156→                  const path = normalizeToRelativePath(edit.file_path);
157→                  if (!seenPaths.has(path)) {
158→                    seenPaths.add(path);
159→                    changes.push(createFileChange('Edit', path));
160→                  }
161→                }
162→              }
163→            }
164→          }
165→        }
166→      } catch {
167→        // Skip invalid JSON lines
168→      }
169→    }
170→
171→    return changes;
172→  } catch (error) {
173→    console.error('[ChangeDetection] Error parsing transcript:', error);
174→    return [];
175→  }
176→}
177→
178→/**
179→ * Normalize an absolute path to relative (to PAI_DIR).
180→ */
181→function normalizeToRelativePath(absolutePath: string): string {
182→  if (absolutePath.startsWith(PAI_DIR)) {
183→    return relative(PAI_DIR, absolutePath);
184→  }
185→  return absolutePath;
186→}
187→
188→/**
189→ * Create a FileChange object with categorization.
190→ */
191→function createFileChange(tool: 'Write' | 'Edit', path: string): FileChange {
192→  return {
193→    tool,
194→    path,
195→    category: categorizeChange(path),
196→    isPhilosophical: isPhilosophicalPath(path),
197→    isStructural: isStructuralPath(path),
198→  };
199→}
200→
201→// ============================================================================
202→// Change Categorization
203→// ============================================================================
204→
205→/**
206→ * Categorize a file path by its location in the PAI system.
207→ */
208→export function categorizeChange(path: string): ChangeCategory | null {
209→  // Check exclusions first
210→  for (const excluded of EXCLUDED_PATHS) {
211→    if (path.includes(excluded)) {
212→      return null;
213→    }
214→  }
215→
216→  // Check if path is within PAI directory
217→  const absolutePath = path.startsWith('/') ? path : join(PAI_DIR, path);
218→  if (!absolutePath.startsWith(PAI_DIR)) {
219→    return null;
220→  }
221→
222→  // Categorize by path pattern
223→  if (path.includes('skills/')) {
224→    // Exclude personal/private skills (prefixed with _ by convention)
225→    const skillMatch = path.match(/skills\/(_[^/]+)/);
226→    if (skillMatch) return null;
227→    if (path.includes('/Workflows/')) return 'workflow';
228→    if (path.includes('skills/PAI/')) return 'core-system';
229→    return 'skill';
230→  }
231→
232→  if (path.includes('hooks/')) return 'hook';
233→  if (path.includes('MEMORY/PAISYSTEMUPDATES/')) return 'documentation';
234→  if (path.includes('MEMORY/')) return 'memory-system';
235→  if (path.endsWith('settings.json')) return 'config';
236→  if (path.endsWith('.md') && !path.includes('WORK/')) return 'documentation';
237→
238→  return null;
239→}
240→
241→/**
242→ * Check if a path represents philosophical/architectural content.
243→ */
244→function isPhilosophicalPath(path: string): boolean {
245→  for (const pattern of PHILOSOPHICAL_PATTERNS) {
246→    if (pattern.test(path)) return true;
247→  }
248→  for (const highPriority of HIGH_PRIORITY_PATHS) {
249→    if (path.includes(highPriority)) return true;
250→  }
251→  return false;
252→}
253→
254→/**
255→ * Check if a path represents structural content (SKILL.md, workflows, config).
256→ */
257→function isStructuralPath(path: string): boolean {
258→  for (const pattern of STRUCTURAL_PATTERNS) {
259→    if (pattern.test(path)) return true;
260→  }
261→  return false;
262→}
