264→// ============================================================================
265→// Significance Detection
266→// ============================================================================
267→
268→/**
269→ * Determine if changes are significant enough to warrant background integrity check.
270→ */
271→export function isSignificantChange(changes: FileChange[]): boolean {
272→  // Filter to only PAI system changes
273→  const systemChanges = changes.filter(c => c.category !== null);
274→
275→  if (systemChanges.length === 0) return false;
276→
277→  // Always significant if philosophical or structural changes
278→  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
279→    return true;
280→  }
281→
282→  // Significant if multiple files in same domain
283→  const categories = new Set(systemChanges.map(c => c.category));
284→  if (categories.size >= 1 && systemChanges.length >= 2) {
285→    return true;
286→  }
287→
288→  // Significant if any skill, hook, or core-system change
289→  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'core-system', 'workflow'];
290→  if (systemChanges.some(c => importantCategories.includes(c.category!))) {
291→    return true;
292→  }
293→
294→  return false;
295→}
296→
297→/**
298→ * Check if changes warrant documentation.
299→ * UPDATED: Lower thresholds for more granular, frequent documentation.
300→ * Philosophy: File system is cheap, more signal is valuable.
301→ */
302→export function shouldDocumentChanges(changes: FileChange[]): boolean {
303→  const systemChanges = changes.filter(c => c.category !== null);
304→
305→  // No changes to document
306→  if (systemChanges.length === 0) return false;
307→
308→  // Always document philosophical or structural changes
309→  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
310→    return true;
311→  }
312→
313→  // Document ANY skill, hook, workflow, core-system, or config change
314→  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'workflow', 'core-system', 'config'];
315→  if (systemChanges.some(c => c.category && importantCategories.includes(c.category))) {
316→    return true;
317→  }
318→
319→  // Document if 2+ files changed (lowered from 3+)
320→  if (systemChanges.length >= 2) {
321→    return true;
322→  }
323→
324→  // Document new file creation in system areas
325→  const newFiles = systemChanges.filter(c => c.tool === 'Write');
326→  if (newFiles.length > 0) return true;
327→
328→  // Document any tool file changes (.ts in Tools/)
329→  if (systemChanges.some(c => c.path.includes('/Tools/') && c.path.endsWith('.ts'))) {
330→    return true;
331→  }
332→
333→  return false;
334→}
