336→// ============================================================================
337→// Throttling
338→// ============================================================================
339→
340→// Reduced from 5 to 2 minutes for more frequent documentation updates
341→const COOLDOWN_MINUTES = 2;
342→
343→/**
344→ * Read the current integrity state.
345→ */
346→export function readIntegrityState(): IntegrityState | null {
347→  try {
348→    if (!existsSync(STATE_FILE)) return null;
349→    const content = readFileSync(STATE_FILE, 'utf-8');
350→    return JSON.parse(content);
351→  } catch {
352→    return null;
353→  }
354→}
355→
356→/**
357→ * Check if we're within the cooldown period.
358→ */
359→export function isInCooldown(): boolean {
360→  const state = readIntegrityState();
361→  if (!state?.cooldown_until) return false;
362→
363→  const cooldownUntil = new Date(state.cooldown_until);
364→  return new Date() < cooldownUntil;
365→}
366→
367→/**
368→ * Generate a hash of changes for deduplication.
369→ */
370→export function hashChanges(changes: FileChange[]): string {
371→  const sorted = changes
372→    .map(c => `${c.tool}:${c.path}`)
373→    .sort()
374→    .join('|');
375→
376→  // Simple hash
377→  let hash = 0;
378→  for (let i = 0; i < sorted.length; i++) {
379→    const char = sorted.charCodeAt(i);
380→    hash = ((hash << 5) - hash) + char;
381→    hash = hash & hash;
382→  }
383→  return hash.toString(16);
384→}
385→
386→/**
387→ * Check if changes are duplicates of the last run.
388→ */
389→export function isDuplicateRun(changes: FileChange[]): boolean {
390→  const state = readIntegrityState();
391→  if (!state?.last_changes_hash) return false;
392→
393→  const currentHash = hashChanges(changes);
394→  return currentHash === state.last_changes_hash;
395→}
396→
397→/**
398→ * Get the cooldown end time.
399→ */
400→export function getCooldownEndTime(): string {
401→  const now = new Date();
402→  now.setMinutes(now.getMinutes() + COOLDOWN_MINUTES);
403→  return now.toISOString();
404→}
