406→// ============================================================================
407→// Significance and Change Type Determination
408→// ============================================================================
409→
410→/**
411→ * Determine the significance label based on change characteristics.
412→ */
413→export function determineSignificance(changes: FileChange[]): SignificanceLabel {
414→  const count = changes.length;
415→  const hasStructural = changes.some(c => c.isStructural);
416→  const hasPhilosophical = changes.some(c => c.isPhilosophical);
417→  const hasNewFiles = changes.some(c => c.tool === 'Write');
418→
419→  const categories = new Set(changes.map(c => c.category).filter(Boolean));
420→  const hasCoreSystem = changes.some(c => c.category === 'core-system');
421→  const hasHooks = changes.some(c => c.category === 'hook');
422→  const hasSkills = changes.some(c => c.category === 'skill');
423→
424→  // Critical: breaking changes, major restructuring
425→  if (hasStructural && hasPhilosophical && count >= 5) {
426→    return 'critical';
427→  }
428→
429→  // Major: new skills/workflows, architectural decisions
430→  if (hasNewFiles && (hasStructural || hasPhilosophical)) {
431→    return 'major';
432→  }
433→  if (hasCoreSystem || (categories.size >= 3)) {
434→    return 'major';
435→  }
436→  if (hasHooks && count >= 3) {
437→    return 'major';
438→  }
439→
440→  // Moderate: multi-file updates, small features
441→  if (count >= 3 || categories.size >= 2) {
442→    return 'moderate';
443→  }
444→  if (hasSkills && count >= 2) {
445→    return 'moderate';
446→  }
447→
448→  // Minor: single file doc updates
449→  if (count === 1 && !hasStructural && !hasPhilosophical) {
450→    return 'minor';
451→  }
452→
453→  // Trivial: only if very small doc changes
454→  if (count === 1 && changes[0].category === 'documentation') {
455→    return 'trivial';
456→  }
457→
458→  return 'minor';
459→}
460→
461→/**
462→ * Determine the change type based on affected files.
463→ */
464→export function inferChangeType(changes: FileChange[]): ChangeType {
465→  const categories = changes.map(c => c.category).filter(Boolean);
466→  const uniqueCategories = new Set(categories);
467→
468→  // Multi-area if touching 3+ categories
469→  if (uniqueCategories.size >= 3) {
470→    return 'multi_area';
471→  }
472→
473→  // Single category cases
474→  if (uniqueCategories.size === 1) {
475→    const cat = [...uniqueCategories][0];
476→    switch (cat) {
477→      case 'skill': return changes.some(c => c.isStructural) ? 'structure_change' : 'skill_update';
478→      case 'hook': return 'hook_update';
479→      case 'workflow': return 'workflow_update';
480→      case 'config': return 'config_update';
481→      case 'core-system': return 'structure_change';
482→      case 'documentation': return 'doc_update';
483→      default: return 'skill_update';
484→    }
485→  }
486→
487→  // Two categories - pick the more significant one
488→  if (uniqueCategories.has('hook')) return 'hook_update';
489→  if (uniqueCategories.has('skill')) return 'skill_update';
490→  if (uniqueCategories.has('workflow')) return 'workflow_update';
491→  if (uniqueCategories.has('config')) return 'config_update';
492→
493→  return 'multi_area';
494→}
