496→/**
497→ * Generate a descriptive 4-8 word title based on the changes.
498→ */
499→export function generateDescriptiveTitle(changes: FileChange[]): string {
500→  const paths = changes.map(c => c.path);
501→
502→  // Extract skill names
503→  const skillNames = new Set<string>();
504→  for (const p of paths) {
505→    const match = p.match(/skills\/([^/]+)\//);
506→    if (match && match[1] !== 'PAI') skillNames.add(match[1]);
507→  }
508→
509→  // Detect file types
510→  const hasSkillMd = paths.some(p => p.endsWith('SKILL.md'));
511→  const hasWorkflows = paths.some(p => p.includes('/Workflows/'));
512→  const hasTools = paths.some(p => p.includes('/Tools/') && p.endsWith('.ts'));
513→  const hasHooks = paths.some(p => p.includes('hooks/'));
514→  const hasConfig = paths.some(p => p.endsWith('settings.json'));
515→  const hasCoreSystem = paths.some(p => p.includes('skills/PAI/'));
516→  const hasCoreUser = paths.some(p => p.includes('PAI/USER/'));
517→
518→  let title = '';
519→
520→  // Single skill update
521→  if (skillNames.size === 1) {
522→    const skill = [...skillNames][0];
523→    if (hasSkillMd) {
524→      title = `${skill} Skill Definition Update`;
525→    } else if (hasWorkflows) {
526→      const workflowNames = paths
527→        .filter(p => p.includes('/Workflows/'))
528→        .map(p => basename(p, '.md'));
529→      if (workflowNames.length === 1) {
530→        title = `${skill} ${workflowNames[0]} Workflow Update`;
531→      } else {
532→        title = `${skill} Workflows Updated`;
533→      }
534→    } else if (hasTools) {
535→      const toolNames = paths
536→        .filter(p => p.includes('/Tools/'))
537→        .map(p => basename(p, '.ts'));
538→      if (toolNames.length === 1) {
539→        title = `${skill} ${toolNames[0]} Tool Update`;
540→      } else {
541→        title = `${skill} Tools Updated`;
542→      }
543→    } else {
544→      title = `${skill} Skill Files Updated`;
545→    }
546→  }
547→  // Multiple skills
548→  else if (skillNames.size > 1 && skillNames.size <= 3) {
549→    const skills = [...skillNames].slice(0, 3).join(' and ');
550→    title = `${skills} Skills Updated`;
551→  }
552→  // Hook changes
553→  else if (hasHooks) {
554→    const hookNames = paths
555→      .filter(p => p.includes('hooks/'))
556→      .map(p => basename(p, '.ts').replace('.hook', ''));
557→    if (hookNames.length === 1) {
558→      title = `${hookNames[0]} Hook Updated`;
559→    } else if (hookNames.length <= 3) {
560→      title = `${hookNames.slice(0, 3).join(', ')} Hooks Updated`;
561→    } else {
562→      title = `Hook System Updates`;
563→    }
564→  }
565→  // Config changes
566→  else if (hasConfig) {
567→    title = 'System Configuration Updated';
568→  }
569→  // Core system changes
570→  else if (hasCoreSystem) {
571→    const docNames = paths
572→      .filter(p => p.includes('skills/PAI/'))
573→      .map(p => basename(p, '.md'));
574→    if (docNames.length === 1) {
575→      title = `${docNames[0]} Documentation Updated`;
576→    } else {
577→      title = 'PAI System Documentation Updated';
578→    }
579→  }
580→  // Core user changes
581→  else if (hasCoreUser) {
582→    const docNames = paths
583→      .filter(p => p.includes('PAI/USER/'))
584→      .map(p => basename(p, '.md'));
585→    if (docNames.length === 1) {
586→      title = `${docNames[0]} User Config Updated`;
587→    } else {
588→      title = 'User Configuration Updated';
589→    }
590→  }
591→  // Fallback
592→  else {
593→    const categories = new Set(changes.map(c => c.category).filter(Boolean));
594→    if (categories.size === 1) {
595→      const cat = [...categories][0];
596→      title = `${capitalize(cat || 'System')} Updates Applied`;
597→    } else {
598→      title = 'Multi-Area System Updates Applied';
599→    }
600→  }
601→
602→  // Ensure 4-8 words
603→  const words = title.split(/\s+/);
604→  if (words.length < 4) {
605→    title = `PAI ${title}`;
606→  } else if (words.length > 8) {
607→    title = words.slice(0, 8).join(' ');
608→  }
609→
610→  return title;
611→}
612→
613→function capitalize(s: string): string {
614→  return s.charAt(0).toUpperCase() + s.slice(1);
615→}
