  1→#!/usr/bin/env bun
  2→/**
  3→ * Metadata Extraction Library for UOCS Enhancement
  4→ *
  5→ * Extracts agent instance IDs, parent-child relationships, and session info
  6→ * from Task tool calls and other tool inputs.
  7→ *
  8→ * Design Philosophy: Optional extraction with graceful fallbacks
  9→ * - If instance IDs are present in descriptions/prompts, extract them
 10→ * - If not present, fall back to agent type only
 11→ * - Never fail - always return usable metadata
 12→ */
 13→
 14→export interface AgentInstanceMetadata {
 15→  agent_instance_id?: string;      // "perplexity-researcher-1" (full ID)
 16→  agent_type?: string;              // "perplexity-researcher" (base type)
 17→  instance_number?: number;         // 1 (sequence number)
 18→  parent_session_id?: string;       // Session that spawned this agent
 19→  parent_task_id?: string;          // Task ID that spawned this agent
 20→}
 21→
 22→/**
 23→ * Extract agent instance ID from Task tool input
 24→ *
 25→ * Looks for patterns in priority order:
 26→ * 1. [agent-type-N] in description (e.g., "Research topic [perplexity-researcher-1]")
 27→ * 2. [AGENT_INSTANCE: agent-type-N] in prompt
 28→ * 3. subagent_type field (fallback to just type, no instance number)
 29→ *
 30→ * @param toolInput The tool input object from PreToolUse/PostToolUse hooks
 31→ * @param description Optional description field from tool input
 32→ * @returns Metadata object with extracted information
 33→ */
 34→export function extractAgentInstanceId(
 35→  toolInput: any,
 36→  description?: string
 37→): AgentInstanceMetadata {
 38→  const result: AgentInstanceMetadata = {};
 39→
 40→  // Strategy 1: Extract from description [agent-type-N]
 41→  // Example: "Research consumer complaints [perplexity-researcher-1]"
 42→  if (description) {
 43→    const descMatch = description.match(/\[([a-z-]+-researcher)-(\d+)\]/);
 44→    if (descMatch) {
 45→      result.agent_type = descMatch[1];
 46→      result.instance_number = parseInt(descMatch[2], 10);
 47→      result.agent_instance_id = `${result.agent_type}-${result.instance_number}`;
 48→    }
 49→  }
 50→
 51→  // Strategy 2: Extract from prompt [AGENT_INSTANCE: ...]
 52→  // Example: "[AGENT_INSTANCE: perplexity-researcher-1]"
 53→  if (!result.agent_instance_id && toolInput?.prompt && typeof toolInput.prompt === 'string') {
 54→    const promptMatch = toolInput.prompt.match(/\[AGENT_INSTANCE:\s*([^\]]+)\]/);
 55→    if (promptMatch) {
 56→      result.agent_instance_id = promptMatch[1].trim();
 57→
 58→      // Parse agent type and instance number from ID
 59→      const parts = result.agent_instance_id.match(/^([a-z-]+)-(\d+)$/);
 60→      if (parts) {
 61→        result.agent_type = parts[1];
 62→        result.instance_number = parseInt(parts[2], 10);
 63→      }
 64→    }
 65→  }
 66→
 67→  // Strategy 3: Extract parent session from prompt
 68→  // Example: "[PARENT_SESSION: b7062b5a-03d3-4168-9555-a748e0b2efa3]"
 69→  if (toolInput?.prompt && typeof toolInput.prompt === 'string') {
 70→    const parentSessionMatch = toolInput.prompt.match(/\[PARENT_SESSION:\s*([^\]]+)\]/);
 71→    if (parentSessionMatch) {
 72→      result.parent_session_id = parentSessionMatch[1].trim();
 73→    }
 74→
 75→    // Extract parent task from prompt
 76→    // Example: "[PARENT_TASK: research_1731445892345]"
 77→    const parentTaskMatch = toolInput.prompt.match(/\[PARENT_TASK:\s*([^\]]+)\]/);
 78→    if (parentTaskMatch) {
 79→      result.parent_task_id = parentTaskMatch[1].trim();
 80→    }
 81→  }
 82→
 83→  // Strategy 4: Fallback to subagent_type if available (no instance number)
 84→  // This ensures we at least capture the agent type even without instance IDs
 85→  if (!result.agent_type && toolInput?.subagent_type) {
 86→    result.agent_type = toolInput.subagent_type;
 87→  }
 88→
 89→  return result;
 90→}
 91→
 92→/**
 93→ * Enrich event with agent metadata
 94→ *
 95→ * Takes a base event object and adds agent instance metadata to it.
 96→ * Returns a new object with merged metadata.
 97→ *
 98→ * @param event Base event object (from PreToolUse/PostToolUse)
 99→ * @param toolInput Tool input object
100→ * @param description Optional description field
101→ * @returns Enriched event with agent metadata
102→ */
103→export function enrichEventWithAgentMetadata(
104→  event: any,
105→  toolInput: any,
106→  description?: string
107→): any {
108→  const metadata = extractAgentInstanceId(toolInput, description);
109→
110→  // Only add fields that have values (keep events clean)
111→  const enrichedEvent = { ...event };
112→
113→  if (metadata.agent_instance_id) {
114→    enrichedEvent.agent_instance_id = metadata.agent_instance_id;
115→  }
116→
117→  if (metadata.agent_type) {
118→    enrichedEvent.agent_type = metadata.agent_type;
119→  }
120→
121→  if (metadata.instance_number !== undefined) {
122→    enrichedEvent.instance_number = metadata.instance_number;
123→  }
124→
125→  if (metadata.parent_session_id) {
126→    enrichedEvent.parent_session_id = metadata.parent_session_id;
127→  }
128→
129→  if (metadata.parent_task_id) {
130→    enrichedEvent.parent_task_id = metadata.parent_task_id;
131→  }
132→
133→  return enrichedEvent;
134→}
135→
136→/**
137→ * Check if a tool call is spawning a subagent
138→ *
139→ * @param toolName Name of the tool being called
140→ * @param toolInput Tool input object
141→ * @returns true if this is a Task tool call spawning an agent
142→ */
143→export function isAgentSpawningCall(toolName: string, toolInput: any): boolean {
144→  return toolName === 'Task' && toolInput?.subagent_type !== undefined;
145→}
