  1→/**
  2→ * Notification Service — ntfy + voice only
  3→ *
  4→ * Simplified from multi-channel (Discord, Twilio, Desktop) to just ntfy push.
  5→ * Voice notifications are handled by the voice server (localhost:8888).
  6→ *
  7→ * Design principles:
  8→ * - Async, non-blocking (fire-and-forget)
  9→ * - Fail gracefully (never block hook execution)
 10→ * - Expandable later if needed
 11→ */
 12→
 13→import { readFileSync, writeFileSync, existsSync } from 'fs';
 14→import { join } from 'path';
 15→import { homedir } from 'os';
 16→import { getIdentity } from './identity';
 17→
 18→// ============================================================================
 19→// Types
 20→// ============================================================================
 21→
 22→export type NotificationPriority = 'min' | 'low' | 'default' | 'high' | 'urgent';
 23→
 24→export type NotificationEvent =
 25→  | 'taskComplete'
 26→  | 'longTask'
 27→  | 'backgroundAgent'
 28→  | 'error'
 29→  | 'security';
 30→
 31→export interface NotificationOptions {
 32→  title?: string;
 33→  priority?: NotificationPriority;
 34→  tags?: string[];
 35→  click?: string;
 36→  actions?: Array<{
 37→    action: 'view' | 'http';
 38→    label: string;
 39→    url: string;
 40→  }>;
 41→}
 42→
 43→export interface NotificationConfig {
 44→  ntfy: {
 45→    enabled: boolean;
 46→    topic: string;
 47→    server: string;
 48→  };
 49→  thresholds: {
 50→    longTaskMinutes: number;
 51→  };
 52→  routing: {
 53→    [key in NotificationEvent]: ('ntfy')[];
 54→  };
 55→}
 56→
 57→// ============================================================================
 58→// Configuration
 59→// ============================================================================
 60→
 61→const DEFAULT_CONFIG: NotificationConfig = {
 62→  ntfy: {
 63→    enabled: false,
 64→    topic: '',
 65→    server: 'ntfy.sh'
 66→  },
 67→  thresholds: {
 68→    longTaskMinutes: 5
 69→  },
 70→  routing: {
 71→    taskComplete: [],
 72→    longTask: ['ntfy'],
 73→    backgroundAgent: ['ntfy'],
 74→    error: ['ntfy'],
 75→    security: ['ntfy']
 76→  }
 77→};
 78→
 79→function expandEnvVars(content: string): string {
 80→  return content.replace(/\$\{(\w+)\}/g, (_, key) => process.env[key] || '');
 81→}
 82→
 83→export function getNotificationConfig(): NotificationConfig {
 84→  try {
 85→    const paiDir = process.env.PAI_DIR || join(homedir(), '.claude');
 86→    const settingsPath = join(paiDir, 'settings.json');
 87→
 88→    if (existsSync(settingsPath)) {
 89→      const rawContent = readFileSync(settingsPath, 'utf-8');
 90→      const expandedContent = expandEnvVars(rawContent);
 91→      const settings = JSON.parse(expandedContent);
 92→      if (settings.notifications) {
 93→        return {
 94→          ...DEFAULT_CONFIG,
 95→          ntfy: { ...DEFAULT_CONFIG.ntfy, ...settings.notifications?.ntfy },
 96→          thresholds: { ...DEFAULT_CONFIG.thresholds, ...settings.notifications?.thresholds },
 97→          routing: { ...DEFAULT_CONFIG.routing, ...settings.notifications?.routing }
 98→        };
 99→      }
100→    }
101→  } catch (error) {
102→    console.error('Failed to load notification config:', error);
103→  }
104→
105→  return DEFAULT_CONFIG;
106→}
107→
108→// ============================================================================
109→// Session Timing
110→// ============================================================================
111→
112→const SESSION_START_FILE = '/tmp/pai-session-start.txt';
113→
114→export function recordSessionStart(): void {
115→  try { writeFileSync(SESSION_START_FILE, Date.now().toString()); } catch {}
116→}
117→
118→export function getSessionDurationMinutes(): number {
119→  try {
120→    if (existsSync(SESSION_START_FILE)) {
121→      const startTime = parseInt(readFileSync(SESSION_START_FILE, 'utf-8'));
122→      return (Date.now() - startTime) / 1000 / 60;
123→    }
124→  } catch {}
125→  return 0;
126→}
127→
128→export function isLongRunningTask(): boolean {
129→  const config = getNotificationConfig();
130→  return getSessionDurationMinutes() >= config.thresholds.longTaskMinutes;
131→}
132→
133→// ============================================================================
134→// ntfy Push
135→// ============================================================================
136→
137→export async function sendPush(
138→  message: string,
139→  options: NotificationOptions = {}
140→): Promise<boolean> {
141→  const config = getNotificationConfig();
142→
143→  if (!config.ntfy.enabled || !config.ntfy.topic) {
144→    return false;
145→  }
146→
147→  try {
148→    const url = `https://${config.ntfy.server}/${config.ntfy.topic}`;
149→
150→    const headers: Record<string, string> = {
151→      'Content-Type': 'text/plain',
152→    };
153→
154→    if (options.title) headers['Title'] = options.title;
155→
156→    if (options.priority) {
157→      const priorityMap: Record<NotificationPriority, string> = {
158→        'min': '1', 'low': '2', 'default': '3', 'high': '4', 'urgent': '5'
159→      };
160→      headers['Priority'] = priorityMap[options.priority] || '3';
161→    }
162→
163→    if (options.tags?.length) headers['Tags'] = options.tags.join(',');
164→    if (options.click) headers['Click'] = options.click;
165→
166→    if (options.actions?.length) {
167→      headers['Actions'] = options.actions
168→        .map(a => `${a.action}, ${a.label}, ${a.url}`)
169→        .join('; ');
170→    }
171→
172→    const response = await fetch(url, {
173→      method: 'POST',
174→      headers,
175→      body: message,
176→      signal: AbortSignal.timeout(5000),
177→    });
178→
179→    return response.ok;
180→  } catch (error) {
181→    console.error('ntfy send failed:', error);
182→    return false;
183→  }
184→}
185→
186→// ============================================================================
187→// Smart Router
188→// ============================================================================
189→
190→export async function notify(
191→  event: NotificationEvent,
192→  message: string,
193→  options: NotificationOptions = {}
194→): Promise<void> {
195→  const config = getNotificationConfig();
196→  const channels = config.routing[event] || [];
197→
198→  for (const channel of channels) {
199→    if (channel === 'ntfy') {
200→      sendPush(message, {
201→        title: options.title || getDefaultTitle(event),
202→        priority: options.priority || getDefaultPriority(event),
203→        tags: options.tags || getDefaultTags(event),
204→        ...options
205→      }).catch(() => {});
206→    }
207→  }
208→}
209→
210→export async function notifyTaskComplete(message: string, options: NotificationOptions = {}): Promise<void> {
211→  const event: NotificationEvent = isLongRunningTask() ? 'longTask' : 'taskComplete';
212→  await notify(event, message, options);
213→}
214→
215→export async function notifyBackgroundAgent(
216→  agentType: string,
217→  message: string,
218→  options: NotificationOptions = {}
219→): Promise<void> {
220→  await notify('backgroundAgent', message, {
221→    title: `${agentType} Agent Complete`,
222→    tags: ['robot', 'white_check_mark'],
223→    ...options
224→  });
225→}
226→
227→export async function notifyError(message: string, options: NotificationOptions = {}): Promise<void> {
228→  await notify('error', message, {
229→    priority: 'high',
230→    tags: ['warning', 'x'],
231→    ...options
232→  });
233→}
234→
235→// ============================================================================
236→// Helpers
237→// ============================================================================
238→
239→function getDefaultTitle(event: NotificationEvent): string {
240→  const DA_NAME = getIdentity().name;
241→  const titles: Record<NotificationEvent, string> = {
242→    taskComplete: DA_NAME,
243→    longTask: `${DA_NAME} - Task Complete`,
244→    backgroundAgent: `${DA_NAME} - Agent Complete`,
245→    error: `${DA_NAME} - Error`,
246→    security: `${DA_NAME} - Security Alert`
247→  };
248→  return titles[event];
249→}
250→
251→function getDefaultPriority(event: NotificationEvent): NotificationPriority {
252→  const priorities: Record<NotificationEvent, NotificationPriority> = {
253→    taskComplete: 'default',
254→    longTask: 'default',
255→    backgroundAgent: 'default',
256→    error: 'high',
257→    security: 'urgent'
258→  };
259→  return priorities[event];
260→}
261→
262→function getDefaultTags(event: NotificationEvent): string[] {
263→  const tags: Record<NotificationEvent, string[]> = {
264→    taskComplete: ['white_check_mark'],
265→    longTask: ['hourglass', 'white_check_mark'],
266→    backgroundAgent: ['robot', 'white_check_mark'],
267→    error: ['warning', 'x'],
268→    security: ['rotating_light', 'lock']
269→  };
270→  return tags[event];
271→}
