  1→/**
  2→ * output-validators.ts - Validation for voice and tab title outputs
  3→ *
  4→ * Single source of truth for what constitutes valid/invalid output
  5→ * in the voice and tab title systems. NOT related to Algorithm format.
  6→ *
  7→ * Tab title validators enforce the state machine:
  8→ *   - Working titles (⚙️): gerund start ("Fixing auth bug.")
  9→ *   - Completion titles (✓): past tense, NO gerund ("Fixed auth bug.")
 10→ *   - Question titles: noun phrase, no period ("Auth method")
 11→ *
 12→ * Renamed from response-format.ts (v0.2.32) — old name was misleading.
 13→ */
 14→
 15→// Conversational filler — always invalid for voice output
 16→const GARBAGE_PATTERNS = [
 17→  /appreciate/i,
 18→  /thank/i,
 19→  /welcome/i,
 20→  /help(ing)? you/i,
 21→  /assist(ing)? you/i,
 22→  /reaching out/i,
 23→  /happy to/i,
 24→  /let me know/i,
 25→  /feel free/i,
 26→];
 27→
 28→// Conversational starters — not factual summaries
 29→const CONVERSATIONAL_STARTERS = [
 30→  /^I'm /i, /^I am /i, /^Sure[,.]?/i, /^OK[,.]?/i,
 31→  /^Got it[,.]?/i, /^Done\.?$/i, /^Yes[,.]?/i, /^No[,.]?/i,
 32→  /^Okay[,.]?/i, /^Alright[,.]?/i,
 33→];
 34→
 35→// Single-word garbage
 36→const SINGLE_WORD_BLOCKLIST = new Set([
 37→  'ready', 'done', 'ok', 'okay', 'yes', 'no', 'sure',
 38→  'hello', 'hi', 'hey', 'thanks', 'working', 'processing',
 39→]);
 40→
 41→/**
 42→ * Check if a voice completion is valid for TTS.
 43→ */
 44→export function isValidVoiceCompletion(text: string): boolean {
 45→  if (!text || text.length < 10) return false;
 46→  const wordCount = text.trim().split(/\s+/).length;
 47→  if (wordCount === 1) {
 48→    const lower = text.toLowerCase().replace(/[^a-z]/g, '');
 49→    if (SINGLE_WORD_BLOCKLIST.has(lower) || lower.length < 10) return false;
 50→  }
 51→  for (const p of GARBAGE_PATTERNS) if (p.test(text)) return false;
 52→  if (text.length < 40) {
 53→    if (/\bready\b/i.test(text) || /\bhello\b/i.test(text)) return false;
 54→  }
 55→  for (const p of CONVERSATIONAL_STARTERS) if (p.test(text)) return false;
 56→  return true;
 57→}
 58→
 59→export function getVoiceFallback(): string {
 60→  return '';
 61→}
 62→
 63→// ─── Tab Title Validation ───────────────────────────────────────
 64→
 65→// Incomplete endings — dangling articles, prepositions, conjunctions
 66→const INCOMPLETE_ENDINGS = new Set([
 67→  'the', 'a', 'an', 'to', 'for', 'with', 'of',
 68→  'in', 'on', 'at', 'by', 'from', 'into', 'about',
 69→  'and', 'or', 'but', 'that', 'which',
 70→]);
 71→
 72→/**
 73→ * Shared base validation: 2-4 words, period, no garbage, no incomplete endings.
 74→ */
 75→function isValidTitleBase(text: string): { valid: boolean; firstWord: string } {
 76→  if (!text || text.length < 5) return { valid: false, firstWord: '' };
 77→  if (!text.endsWith('.')) return { valid: false, firstWord: '' };
 78→
 79→  const content = text.slice(0, -1).trim();
 80→  const words = content.split(/\s+/);
 81→  if (words.length < 2 || words.length > 4) return { valid: false, firstWord: '' };
 82→
 83→  const firstWord = words[0].toLowerCase();
 84→
 85→  // Reject generic garbage (both gerund and past-tense forms)
 86→  if (/^(completed?|proces{1,2}e?d|processing|handled|handling|finished|finishing|worked|working|done) (the |on )?(task|request|work|it)$/i.test(content)) {
 87→    return { valid: false, firstWord };
 88→  }
 89→
 90→  // Reject first-person pronouns
 91→  const lower = content.toLowerCase();
 92→  if (/\bi\b/.test(lower) || /\bme\b/.test(lower) || /\bmy\b/.test(lower)) {
 93→    return { valid: false, firstWord };
 94→  }
 95→
 96→  // Reject dangling/incomplete endings
 97→  const lastWord = words[words.length - 1].toLowerCase().replace(/[^a-z]/g, '');
 98→  if (INCOMPLETE_ENDINGS.has(lastWord)) return { valid: false, firstWord };
 99→
100→  return { valid: true, firstWord };
101→}
102→
103→/**
104→ * Working-phase title: MUST start with gerund (-ing verb).
105→ * Used by UpdateTabTitle for 🧠/⚙️ titles.
106→ */
107→export function isValidWorkingTitle(text: string): boolean {
108→  const { valid, firstWord } = isValidTitleBase(text);
109→  if (!valid) return false;
110→  return firstWord.endsWith('ing');
111→}
112→
113→/** @deprecated Use isValidWorkingTitle */
114→export const isValidTabSummary = isValidWorkingTitle;
115→
116→/**
117→ * Completion-phase title: must NOT start with gerund.
118→ * Past tense or other non-gerund verb forms.
119→ * Used by TabState for ✓ titles.
120→ */
121→export function isValidCompletionTitle(text: string): boolean {
122→  const { valid, firstWord } = isValidTitleBase(text);
123→  if (!valid) return false;
124→  // Completion titles must NOT be gerunds — that's a working title
125→  if (firstWord.endsWith('ing')) return false;
126→  return true;
127→}
128→
129→/**
130→ * Question-phase title: noun phrase, no period, 1-4 words, max 30 chars.
131→ */
132→export function isValidQuestionTitle(text: string): boolean {
133→  if (!text || text.trim().length === 0) return false;
134→  if (text.endsWith('.')) return false;
135→  if (text.length > 30) return false;
136→  const words = text.trim().split(/\s+/);
137→  if (words.length < 1 || words.length > 4) return false;
138→  if (/<[^>]*>/.test(text)) return false;
139→  return true;
140→}
141→
142→// ─── Fallbacks ──────────────────────────────────────────────────
143→
144→export function getWorkingFallback(): string {
145→  return 'Processing request.';
146→}
147→
148→export function getCompletionFallback(): string {
149→  return 'Task complete.';
150→}
151→
152→export function getQuestionFallback(): string {
153→  return 'Awaiting input';
154→}
155→
156→/** @deprecated Use getWorkingFallback or getCompletionFallback */
157→export function getTabFallback(stage: 'start' | 'end' = 'start'): string {
158→  return stage === 'end' ? getCompletionFallback() : getWorkingFallback();
159→}
160→
161→// ─── Past Tense Conversion ─────────────────────────────────────
162→
163→const IRREGULAR_PAST: Record<string, string> = {
164→  building: 'Built', running: 'Ran', writing: 'Wrote', reading: 'Read',
165→  making: 'Made', finding: 'Found', getting: 'Got', setting: 'Set',
166→  doing: 'Did', going: 'Went', taking: 'Took', giving: 'Gave',
167→  seeing: 'Saw', sending: 'Sent', thinking: 'Thought', bringing: 'Brought',
168→  beginning: 'Began', breaking: 'Broke', choosing: 'Chose', drawing: 'Drew',
169→  driving: 'Drove', eating: 'Ate', falling: 'Fell', flying: 'Flew',
170→  growing: 'Grew', hiding: 'Hid', holding: 'Held', keeping: 'Kept',
171→  knowing: 'Knew', leading: 'Led', leaving: 'Left', lending: 'Lent',
172→  letting: 'Let', losing: 'Lost', meeting: 'Met', paying: 'Paid',
173→  putting: 'Put', riding: 'Rode', rising: 'Rose', saying: 'Said',
174→  selling: 'Sold', showing: 'Showed', singing: 'Sang', sitting: 'Sat',
175→  sleeping: 'Slept', speaking: 'Spoke', spending: 'Spent', standing: 'Stood',
176→  stealing: 'Stole', striking: 'Struck', sweeping: 'Swept', swimming: 'Swam',
177→  teaching: 'Taught', telling: 'Told', throwing: 'Threw', wearing: 'Wore',
178→  winning: 'Won', understanding: 'Understood',
179→};
180→
181→/**
182→ * Convert a gerund to past tense: "Fixing" → "Fixed", "Building" → "Built".
183→ */
184→export function gerundToPastTense(gerund: string): string {
185→  const lower = gerund.toLowerCase();
186→
187→  // Check irregular map first
188→  if (IRREGULAR_PAST[lower]) return IRREGULAR_PAST[lower];
189→
190→  if (!lower.endsWith('ing') || lower.length < 5) return gerund;
191→  const stem = lower.slice(0, -3);
192→
193→  // Regular: stem + "ed" handles all cases correctly:
194→  // - "fixing" → stem "fix" → "fixed"
195→  // - "stopping" → stem "stopp" → "stopped" (doubled consonant preserved)
196→  // - "processing" → stem "process" → "processed" (natural 'ss' preserved)
197→  const result = stem + 'ed';
198→  return result.charAt(0).toUpperCase() + result.slice(1);
199→}
