 18→/**
 19→ * Generate a PRD filename: PRD-{YYYYMMDD}-{slug}.md
 20→ */
 21→export function generatePRDFilename(slug: string): string {
 22→  const now = new Date();
 23→  const y = now.getFullYear();
 24→  const m = String(now.getMonth() + 1).padStart(2, "0");
 25→  const d = String(now.getDate()).padStart(2, "0");
 26→  return `PRD-${y}${m}${d}-${slug}.md`;
 27→}
