 29→/**
 30→ * Generate a PRD ID: PRD-{YYYYMMDD}-{slug}
 31→ */
 32→export function generatePRDId(slug: string): string {
 33→  const now = new Date();
 34→  const y = now.getFullYear();
 35→  const m = String(now.getMonth() + 1).padStart(2, "0");
 36→  const d = String(now.getDate()).padStart(2, "0");
 37→  return `PRD-${y}${m}${d}-${slug}`;
 38→}
