  1→/**
  2→ * tab-setter.ts - Unified tab state setter.
  3→ *
  4→ * Single function that:
  5→ * 1. Sets Kitty tab title and color via remote control
  6→ * 2. Persists per-window state for daemon recovery
  7→ *
  8→ * All hooks call setTabState() instead of directly running kitten commands.
  9→ */
 10→
 11→import { existsSync, writeFileSync, mkdirSync, readdirSync, unlinkSync, readFileSync } from 'fs';
 12→import { join } from 'path';
 13→import { execSync } from 'child_process';
 14→import { TAB_COLORS, PHASE_TAB_CONFIG, ACTIVE_TAB_BG, ACTIVE_TAB_FG, INACTIVE_TAB_FG, type TabState, type AlgorithmTabPhase } from './tab-constants';
 15→import { paiPath } from './paths';
 16→
 17→const TAB_TITLES_DIR = paiPath('MEMORY', 'STATE', 'tab-titles');
 18→const KITTY_SESSIONS_DIR = paiPath('MEMORY', 'STATE', 'kitty-sessions');
 19→
 20→/**
 21→ * Get Kitty environment from env vars or persisted per-session file.
 22→ *
 23→ * Resolution order:
 24→ * 1. Process env vars (direct terminal context — always correct)
 25→ * 2. Per-session file: kitty-sessions/{sessionId}.json (no shared state, no races)
 26→ */
 27→function getKittyEnv(sessionId?: string): { listenOn: string | null; windowId: string | null } {
 28→  // Try environment first (direct terminal calls)
 29→  let listenOn = process.env.KITTY_LISTEN_ON || null;
 30→  let windowId = process.env.KITTY_WINDOW_ID || null;
 31→  if (listenOn && windowId) return { listenOn, windowId };
 32→
 33→  // Per-session file lookup (preferred — no shared mutable state)
 34→  if (sessionId) {
 35→    try {
 36→      const sessionPath = join(KITTY_SESSIONS_DIR, `${sessionId}.json`);
 37→      if (existsSync(sessionPath)) {
 38→        const entry = JSON.parse(readFileSync(sessionPath, 'utf-8'));
 39→        listenOn = listenOn || entry.listenOn || null;
 40→        windowId = windowId || entry.windowId || null;
 41→        if (listenOn && windowId) return { listenOn, windowId };
 42→      }
 43→    } catch { /* silent */ }
 44→  }
 45→
 46→  // Log when kitty env lookup fails with a session ID (diagnostic for compaction issues)
 47→  if (sessionId && !listenOn && !windowId) {
 48→    console.error(`[tab-setter] getKittyEnv: no kitty env found for session ${sessionId.slice(0, 8)} (no env vars, no session file)`);
 49→  }
 50→
 51→  return { listenOn, windowId };
 52→}
 53→
 54→/**
 55→ * Persist a session's Kitty environment for later hook lookups.
 56→ * Called by StartupGreeting at session start.
 57→ *
 58→ * Each session gets its own file: kitty-sessions/{sessionId}.json
 59→ * - No shared mutable state (concurrent session starts are safe)
 60→ * - No unbounded growth (files cleaned up on session end)
 61→ * - Simple atomic write (no read-modify-write cycle)
 62→ *
 63→ */
 64→export function persistKittySession(sessionId: string, listenOn: string, windowId: string): void {
 65→  try {
 66→    if (!existsSync(KITTY_SESSIONS_DIR)) mkdirSync(KITTY_SESSIONS_DIR, { recursive: true });
 67→    writeFileSync(
 68→      join(KITTY_SESSIONS_DIR, `${sessionId}.json`),
 69→      JSON.stringify({ listenOn, windowId }),
 70→      'utf-8'
 71→    );
 72→  } catch { /* silent */ }
 73→}
 74→
 75→/**
 76→ * Remove a session's persisted Kitty environment file.
 77→ * Called by SessionSummary at session end.
 78→ */
 79→export function cleanupKittySession(sessionId: string): void {
 80→  try {
 81→    const sessionPath = join(KITTY_SESSIONS_DIR, `${sessionId}.json`);
 82→    if (existsSync(sessionPath)) unlinkSync(sessionPath);
 83→  } catch { /* silent */ }
 84→}
 85→
 86→interface SetTabOptions {
 87→  title: string;
 88→  state: TabState;
 89→  previousTitle?: string;
 90→  sessionId?: string;
 91→}
 92→
 93→/**
 94→ * Clean up state files for kitty windows that no longer exist.
 95→ * Runs opportunistically on each setTabState call (lightweight).
 96→ */
 97→function cleanupStaleStateFiles(): void {
 98→  try {
 99→    if (!existsSync(TAB_TITLES_DIR)) return;
100→    const files = readdirSync(TAB_TITLES_DIR).filter(f => f.endsWith('.json'));
101→    if (files.length === 0) return;
102→
103→    // Get live window IDs from kitty
104→    const liveOutput = execSync('kitten @ ls 2>/dev/null | jq -r ".[].tabs[].windows[].id" 2>/dev/null', {
105→      encoding: 'utf-8', timeout: 2000,
106→    }).trim();
107→    if (!liveOutput) return;
108→
109→    const liveIds = new Set(liveOutput.split('\n').map(id => id.trim()));
110→
111→    for (const file of files) {
112→      const winId = file.replace('.json', '');
113→      if (!liveIds.has(winId)) {
114→        try { unlinkSync(join(TAB_TITLES_DIR, file)); } catch { /* silent */ }
115→      }
116→    }
117→  } catch { /* silent — cleanup is best-effort */ }
118→}
119→
120→export function setTabState(opts: SetTabOptions): void {
121→  const { title, state, previousTitle, sessionId } = opts;
122→  const colors = TAB_COLORS[state];
123→  const kittyEnv = getKittyEnv(sessionId);
124→
125→  try {
126→    // Need either TERM=xterm-kitty OR a valid KITTY_LISTEN_ON to proceed
127→    const isKitty = process.env.TERM === 'xterm-kitty' || kittyEnv.listenOn;
128→    if (!isKitty) return;
129→
130→    const escaped = title.replace(/"/g, '\\"');
131→    // Set BOTH tab title AND window title. Kitty's tab_title_template uses
132→    // {active_window.title} (the window title). OSC escape codes from Claude Code
133→    // reset set-tab-title overrides, so the template falls back to window title.
134→    // By setting both, our title survives OSC resets.
135→    //
136→    // Use --to flag with KITTY_LISTEN_ON for remote control when not in terminal context
137→    const toFlag = kittyEnv.listenOn ? `--to="${kittyEnv.listenOn}"` : '';
138→    console.error(`[tab-setter] Setting tab: "${escaped}" with toFlag: ${toFlag || '(none)'}`);
139→    execSync(`kitten @ ${toFlag} set-tab-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
140→    execSync(`kitten @ ${toFlag} set-window-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
141→
142→    // For idle state, reset ALL colors to Kitty defaults (no lingering backgrounds)
143→    if (state === 'idle') {
144→      execSync(
145→        `kitten @ ${toFlag} set-tab-color --self active_bg=none active_fg=none inactive_bg=none inactive_fg=none`,
146→        { stdio: 'ignore', timeout: 2000 }
147→      );
148→    } else {
149→      execSync(
150→        `kitten @ ${toFlag} set-tab-color --self active_bg=${ACTIVE_TAB_BG} active_fg=${ACTIVE_TAB_FG} inactive_bg=${colors.inactiveBg} inactive_fg=${INACTIVE_TAB_FG}`,
151→        { stdio: 'ignore', timeout: 2000 }
152→      );
153→    }
154→    console.error(`[tab-setter] Tab commands completed successfully`);
155→  } catch (err) {
156→    console.error(`[tab-setter] Error setting tab:`, err);
157→  }
158→
159→  // Persist per-window state (or clean up on idle/session end)
160→  const windowId = kittyEnv.windowId;
161→  if (!windowId) return;
162→
163→  try {
164→    if (state === 'idle') {
165→      // Session ended — remove state file so no stale data lingers
166→      const statePath = join(TAB_TITLES_DIR, `${windowId}.json`);
167→      if (existsSync(statePath)) unlinkSync(statePath);
168→    } else {
169→      if (!existsSync(TAB_TITLES_DIR)) mkdirSync(TAB_TITLES_DIR, { recursive: true });
170→      const stateData: Record<string, unknown> = {
171→        title,
172→        inactiveBg: colors.inactiveBg,
173→        state,
174→        timestamp: new Date().toISOString(),
175→      };
176→      if (previousTitle) stateData.previousTitle = previousTitle;
177→      writeFileSync(join(TAB_TITLES_DIR, `${windowId}.json`), JSON.stringify(stateData), 'utf-8');
178→    }
179→  } catch { /* silent */ }
180→
181→  // Opportunistic cleanup of stale state files for dead windows
182→  cleanupStaleStateFiles();
183→}
184→
185→/**
186→ * Read per-window state file. Returns null if not found or invalid.
187→ */
188→export function readTabState(sessionId?: string): { title: string; state: TabState; previousTitle?: string; phase?: string } | null {
189→  const kittyEnv = getKittyEnv(sessionId);
190→  const windowId = kittyEnv.windowId;
191→  if (!windowId) return null;
192→  try {
193→    const statePath = join(TAB_TITLES_DIR, `${windowId}.json`);
194→    if (!existsSync(statePath)) return null;
195→    const raw = JSON.parse(require('fs').readFileSync(statePath, 'utf-8'));
196→    return {
197→      title: raw.title || '',
198→      state: raw.state || 'idle',
199→      previousTitle: raw.previousTitle,
200→      phase: raw.phase,
201→    };
202→  } catch { return null; }
203→}
204→
205→/**
206→ * Strip emoji prefix from a tab title to get raw text.
207→ * Handles both working-state prefixes (🧠⚙️✓❓) and Algorithm phase symbols (👁️📋🔨⚡✅📚).
208→ */
209→export function stripPrefix(title: string): string {
210→  return title.replace(/^(?:🧠|⚙️|⚙|✓|❓|👁️|📋|🔨|⚡|✅|📚)\s*/, '').trim();
211→}
212→
213→// Noise words to skip when extracting the session label
214→const SESSION_NOISE = new Set([
215→  'the', 'a', 'an', 'and', 'or', 'for', 'to', 'in', 'on', 'of', 'with',
216→  'my', 'our', 'new', 'old', 'fix', 'add', 'update', 'set', 'get',
217→]);
218→
219→/**
220→ * Extract two representative words from a session name.
221→ * "Tab Title Upgrade" → "TAB TITLE", "Security Redesign" → "SECURITY REDESIGN"
222→ * "Fix Activity Dashboard" → "ACTIVITY DASHBOARD"
223→ * Returns uppercase. Falls back to first two words if all are noise.
224→ */
225→export function getSessionOneWord(sessionId: string): string | null {
226→  try {
227→    const namesPath = paiPath('MEMORY', 'STATE', 'session-names.json');
228→    if (!existsSync(namesPath)) return null;
229→    const names = JSON.parse(readFileSync(namesPath, 'utf-8'));
230→    const fullName = names[sessionId];
231→    if (!fullName) return null;
232→
233→    const words = fullName.split(/\s+/).filter((w: string) => w.length > 0);
234→    if (words.length === 0) return null;
235→
236→    // Collect up to 2 non-noise words
237→    const meaningful = words.filter((w: string) => !SESSION_NOISE.has(w.toLowerCase()));
238→    if (meaningful.length >= 2) {
239→      return `${meaningful[0]} ${meaningful[1]}`.toUpperCase();
240→    } else if (meaningful.length === 1) {
241→      // One meaningful word — grab the next word (even if noise) for context
242→      const idx = words.indexOf(meaningful[0]);
243→      const next = words[idx + 1];
244→      if (next) return `${meaningful[0]} ${next}`.toUpperCase();
245→      return meaningful[0].toUpperCase();
246→    }
247→    // All noise — take first two
248→    return words.slice(0, 2).join(' ').toUpperCase();
249→  } catch {
250→    return null;
251→  }
252→}
253→
254→/**
255→ * Set tab title and color for an Algorithm phase.
256→ * Active format:    {SYMBOL} {ONE_WORD} | {PHASE}
257→ * Complete format:  {ONE_WORD} | {summary}
258→ *
259→ * Called by AlgorithmTracker on phase transitions.
260→ */
261→export function setPhaseTab(phase: AlgorithmTabPhase, sessionId: string, summary?: string): void {
262→  const config = PHASE_TAB_CONFIG[phase];
263→  if (!config) return;
264→
265→  const oneWord = getSessionOneWord(sessionId) || 'WORKING';
266→  const kittyEnv = getKittyEnv(sessionId);
267→
268→  // Build title based on phase
269→  let title: string;
270→  if (phase === 'COMPLETE' && summary) {
271→    title = `✅ ${summary}`;
272→  } else if (phase === 'COMPLETE') {
273→    // No summary extracted — use session name instead of generic "Done."
274→    title = `✅ ${oneWord}`;
275→  } else if (phase === 'IDLE') {
276→    title = oneWord;
277→  } else {
278→    // Preserve existing working description from UpdateTabTitle if available.
279→    // Only swap the emoji prefix to show current phase — keep the real task context.
280→    let existingDesc = '';
281→    const currentState = readTabState(sessionId);
282→    if (currentState?.title) {
283→      const pipeIdx = currentState.title.indexOf('|');
284→      if (pipeIdx !== -1) existingDesc = currentState.title.slice(pipeIdx + 1).trim();
285→    }
286→    const desc = existingDesc || config.gerund;
287→    title = `${config.symbol} ${oneWord} | ${desc}`;
288→  }
289→
290→  try {
291→    const isKitty = process.env.TERM === 'xterm-kitty' || kittyEnv.listenOn;
292→    if (!isKitty) return;
293→
294→    const escaped = title.replace(/"/g, '\\"');
295→    const toFlag = kittyEnv.listenOn ? `--to="${kittyEnv.listenOn}"` : '';
296→
297→    execSync(`kitten @ ${toFlag} set-tab-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
298→    execSync(`kitten @ ${toFlag} set-window-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
299→
300→    if (phase === 'IDLE') {
301→      execSync(
302→        `kitten @ ${toFlag} set-tab-color --self active_bg=none active_fg=none inactive_bg=none inactive_fg=none`,
303→        { stdio: 'ignore', timeout: 2000 }
304→      );
305→    } else {
306→      execSync(
307→        `kitten @ ${toFlag} set-tab-color --self active_bg=${ACTIVE_TAB_BG} active_fg=${ACTIVE_TAB_FG} inactive_bg=${config.inactiveBg} inactive_fg=${INACTIVE_TAB_FG}`,
308→        { stdio: 'ignore', timeout: 2000 }
309→      );
310→    }
311→    console.error(`[tab-setter] Phase tab: "${escaped}" (${phase}, bg=${config.inactiveBg})`);
312→  } catch (err) {
313→    console.error(`[tab-setter] Error setting phase tab:`, err);
314→  }
315→
316→  // Persist per-window state
317→  const windowId = kittyEnv.windowId;
318→  if (!windowId) return;
319→
320→  try {
321→    if (!existsSync(TAB_TITLES_DIR)) mkdirSync(TAB_TITLES_DIR, { recursive: true });
322→    writeFileSync(join(TAB_TITLES_DIR, `${windowId}.json`), JSON.stringify({
323→      title,
324→      inactiveBg: config.inactiveBg,
325→      state: phase === 'COMPLETE' ? 'completed' : 'working',
326→      phase,
327→      timestamp: new Date().toISOString(),
328→    }), 'utf-8');
329→  } catch { /* silent */ }
330→}
